mapper.select:
SELECT * FROM borrow_records
WHERE student_id = #{studentId} AND status = #{status}
ORDER BY record_id DESC

mapper.update:
UPDATE borrow_records SET
    student_id = #{studentId}, book_id = #{bookId}, borrow_date = #{borrowDate},
